-- Functional seed data for local MySQL.
-- Password note: prefer creating users through auth-service APIs so BCrypt hashes are generated by the application.
-- This script seeds reference/lookup and tenant sample data for DB validation.

CREATE DATABASE IF NOT EXISTS rbf_org_db;
CREATE DATABASE IF NOT EXISTS rbf_auth_db;
CREATE DATABASE IF NOT EXISTS rbf_product_db;
CREATE DATABASE IF NOT EXISTS rbf_inventory_db;
CREATE DATABASE IF NOT EXISTS rbf_billing_db;
CREATE DATABASE IF NOT EXISTS rbf_payment_db;
CREATE DATABASE IF NOT EXISTS rbf_accounting_db;
CREATE DATABASE IF NOT EXISTS rbf_report_db;
CREATE DATABASE IF NOT EXISTS rbf_tax_db;

USE rbf_org_db;
ON DUPLICATE KEY UPDATE name = VALUES(name), email = VALUES(email), updated_at = NOW();

USE rbf_auth_db;
ON DUPLICATE KEY UPDATE permission_name = VALUES(permission_name), active = true;

ON DUPLICATE KEY UPDATE role_level = VALUES(role_level), parent_role_id = VALUES(parent_role_id), active = true;


ON DUPLICATE KEY UPDATE email = VALUES(email), password = VALUES(password);


USE rbf_product_db;
ON DUPLICATE KEY UPDATE name = VALUES(name), updated_at = NOW();

ON DUPLICATE KEY UPDATE price = VALUES(price), gst = VALUES(gst), updated_at = NOW();

USE rbf_inventory_db;
ON DUPLICATE KEY UPDATE quantity = VALUES(quantity), updated_at = NOW();

USE rbf_tax_db;
ON DUPLICATE KEY UPDATE active = true;

ON DUPLICATE KEY UPDATE active = true;

ON DUPLICATE KEY UPDATE active = true;

ON DUPLICATE KEY UPDATE tax_rate = VALUES(tax_rate), active = true, updated_at = NOW();

USE rbf_payment_db;
-- Payments are created by functional API flows.

USE rbf_billing_db;
-- Invoices and invoice_items are created by functional API flows.

USE rbf_accounting_db;
-- Ledger entries are created by billing/accounting API flows.
